return results;

function buildSignString(params) {
  // 1. 过滤参数：排除 sign 和 sign_type，且值非空
  const filteredParams = Object.entries(params).reduce((acc, [key, value]) => {
    if (key === "sign" || key === "sign_type") return acc;

    // 处理空值（空字符串、null、undefined、空数组）
    if (
      value == null ||
      value === "" ||
      (Array.isArray(value) && value.length === 0)
    ) {
      return acc;
    }

    // 2. 值类型处理：对象/数组转为 JSON 字符串，其他类型直接转字符串
    let processedValue;
    if (typeof value === "object" && !Array.isArray(value)) {
      processedValue = JSON.stringify(value); // 对象序列化
    } else if (Array.isArray(value)) {
      processedValue = JSON.stringify(value); // 数组序列化
    } else {
      processedValue = String(value); // 基本类型转字符串
    }

    acc[key] = processedValue;
    return acc;
  }, {});

  // 3. 对键按 ASCII 排序
  const sortedKeys = Object.keys(filteredParams).sort();

  // 4. 拼接为 "key1=value1&key2=value2..." 格式
  return sortedKeys
    .map((key) => `${key}=${filteredParams[key]}`)
    .join("&");
}

// 获取所有输入
const dataItems = $input.all();

// 处理每个输入项
let results = dataItems.map(item => {
  const signString = buildSignString(item.json);
  return { json: { signString } };
});

return results;

const sm3 = require('sm-crypto').sm3;
const signKey="8C8198E3E43E4CF48E7DDD36C05F877A";
// 获取所有输入数据
