    const item = allInputs[i];

    // 从输入中提取stringSignTemp
    const stringSignTemp = item.json.signString;  // 假设stringSignTemp在json里

    // 计算 SM3 哈希
    const hash = sm3(stringSignTemp+signKey);

    // 将结果添加到results数组中
    results.push({
        json: {
            index: item.json.index,  // 保留索引
            hash: hash.toUpperCase()  // 转换为大写
        }
    });
}

return results;

function filterData(dataArray) {
