};

const ex_sn = [
  'M18L', 'W31K', 'W31J', 'W31C', 'B20G',
  'W31F', 'V16B', 'H31A', 'V19A', 'W31H',
  'M18J', 'F01A', 'M18E', 'V19B', 'W31G',
  'M18B', 'B17A'
];

function formatDate(isoString) {
  const date = new Date(isoString);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}
function resolveModelBasedOnSn(serialNumber) {
  if (serialNumber.startsWith('W32')) {
    return 'W332';
  } else if (serialNumber.startsWith('W31')) {
    return 'W331';
  } else if (serialNumber.startsWith('B21')) {
    return 'B21';
  } else if (serialNumber.startsWith('V09')) {
    return 'V09';
  } else if (serialNumber.startsWith('B20')) {
    return 'B20';
  } else if (serialNumber.startsWith('W92')) {
    return 'W942';
  } else if (serialNumber.startsWith('C01')) {
    return 'BY01'; // 定义C01开头的机型为BY01
  } else if (serialNumber.startsWith('W51')) {
    return 'W541';
  } else if (serialNumber.startsWith('W52')) {
    return 'W542';
  } else if (serialNumber.startsWith('W35')) {
    return 'W335';
  }
  return null;
}


for (const item of items) {
  if (item && item.json && typeof item.json.retroid === 'string') {
    const serialNumber = item.json.retroid;
    const skuCode = item.json.sku_code;
    const model = resolveModelBasedOnSn(serialNumber);

    if (ex_sn.includes(serialNumber.substr(0, 4))) {
      // 如果前缀在排除列表中，继续下一个
      continue;
    }

    const productInfo = materialToProductMap[skuCode];
    if (!productInfo) {
      // 如果skuCode不在materialToProductMap中，跳过当前项
      continue;
    }

    if (model !== null && model !== 'FD05' && model !== 'HR01' && model !== 'FD03' && model !== 'FD02') {
      const createTime = item.json.create_time;
      const formattedCreateTime = formatDate(createTime);

      const price = productInfo.price ? productInfo.price.toString() : '未定义';

      results.push({
        json: {
          sn: serialNumber,
          code: productInfo.code,
          name: productInfo.name,
          model: model,
          retailPrice: price,
          createTime: formattedCreateTime
        }
      });
    }
  } else {
    results.push({ json: { error: '输入数据无效或缺少retroid属性' } });
  }
}

return results;

